class HybridBridge(
    private val activity: HybridWebViewActivity,
    private val webView: WebView
) {
    private val prefs: SharedPreferences = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    @JavascriptInterface
    fun ping(): String = "pong"

    @JavascriptInterface
    fun storageSet(key: String, value: String): String {
        prefs.edit().putString(key, value).apply()
        return "ok"
    }

    @JavascriptInterface
    fun storageGet(key: String): String {
        return prefs.getString(key, "") ?: ""
    }

    @JavascriptInterface
    fun storageRemove(key: String): String {
        prefs.edit().remove(key).apply()
        return "ok"
    }

    @JavascriptInterface
    fun storageClear(): String {
        prefs.edit().clear().apply()
        return "ok"
    }

    @JavascriptInterface
    fun pushGetToken(callbackId: String) {
        FirebaseMessaging.getInstance().token
            .addOnSuccessListener { token ->
                emit(callbackId, true, JSONObject().put("token", token))
            }
            .addOnFailureListener { e ->
                emit(callbackId, false, JSONObject().put("error", e.message ?: "Failed to get token"))
            }
    }

    @JavascriptInterface
    fun pushSubscribeToTopic(topic: String, callbackId: String) {
        FirebaseMessaging.getInstance().subscribeToTopic(topic)
            .addOnSuccessListener { emit(callbackId, true, JSONObject().put("topic", topic)) }
            .addOnFailureListener { e -> emit(callbackId, false, JSONObject().put("error", e.message ?: "Failed")) }
    }

    @JavascriptInterface
    fun pushUnsubscribeFromTopic(topic: String, callbackId: String) {
        FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            .addOnSuccessListener { emit(callbackId, true, JSONObject().put("topic", topic)) }
            .addOnFailureListener { e -> emit(callbackId, false, JSONObject().put("error", e.message ?: "Failed")) }
    }

    @JavascriptInterface
    fun cameraRequestPermission(callbackId: String) {
        activity.runOnUiThread {
            activity.requestCameraPermission { granted, error ->
                if (granted) emit(callbackId, true, JSONObject().put("granted", true))
                else emit(callbackId, false, JSONObject().put("granted", false).put("error", error ?: "denied"))
            }
        }
    }

    @JavascriptInterface
    fun cameraPickImage(callbackId: String) {
        activity.runOnUiThread {
            activity.pickImageFromGallery { ok, uriOrError ->
                if (ok) emit(callbackId, true, JSONObject().put("uri", uriOrError))
                else emit(callbackId, false, JSONObject().put("error", uriOrError ?: "failed"))
            }
        }
    }

    @JavascriptInterface
    fun cameraTakePicture(callbackId: String) {
        activity.runOnUiThread {
            activity.requestCameraPermission { granted, error ->
                if (!granted) {
                    emit(callbackId, false, JSONObject().put("error", error ?: "Camera permission denied"))
                    return@requestCameraPermission
                }
                activity.takePicture { ok, uriOrError ->
                    if (ok) emit(callbackId, true, JSONObject().put("uri", uriOrError))
                    else emit(callbackId, false, JSONObject().put("error", uriOrError ?: "failed"))
                }
            }
        }
    }

    @JavascriptInterface
    fun fileReadAsBase64(contentUri: String, callbackId: String) {
        activity.runOnUiThread {
            try {
                val uri = Uri.parse(contentUri)
                val bytes = activity.contentResolver.openInputStream(uri).use { it?.readBytesSafe() } ?: ByteArray(0)
                val b64 = Base64.encodeToString(bytes, Base64.NO_WRAP)
                emit(callbackId, true, JSONObject().put("base64", b64))
            } catch (t: Throwable) {
                emit(callbackId, false, JSONObject().put("error", t.message ?: "read failed"))
            }
        }
    }

    @JavascriptInterface
    fun openExternalUrl(url: String): String {
        return try {
            activity.startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
            "ok"
        } catch (t: Throwable) {
            "error:${t.message}"
        }
    }

    private fun emit(callbackId: String, ok: Boolean, payload: JSONObject) {
        val msg = JSONObject()
            .put("id", callbackId)
            .put("ok", ok)
            .put("payload", payload)

        val js = "window.HybridBridge && window.HybridBridge._nativeCallback && window.HybridBridge._nativeCallback(${msg.toString()});"
        webView.post { webView.evaluateJavascript(js, null) }
    }

    companion object {
        const val JS_NAME = "NativeBridge"
        private const val PREFS_NAME = "hybrid_prefs"
    }
}

private fun InputStream.readBytesSafe(): ByteArray {
    return this.readBytes()
}

object HybridBridgeJsSnippet {
    val script: String = """
        (function () {
          if (window.HybridBridge) return;
          const callbacks = new Map();
          function uuid() {
