          }
          function callNative(method, args) {
            return new Promise((resolve, reject) => {
              const id = uuid();
              callbacks.set(id, { resolve, reject });
              try {
                window.NativeBridge[method].apply(window.NativeBridge, [...args, id]);
              } catch (e) {
                callbacks.delete(id);
                reject(e);
              }
            });
          }
          window.HybridBridge = {
            _nativeCallback: function (msg) {
              try {
                if (!msg || !msg.id) return;
                const cb = callbacks.get(msg.id);
                if (!cb) return;
                callbacks.delete(msg.id);
                if (msg.ok) cb.resolve(msg.payload);
                else cb.reject(msg.payload);
              } catch (e) {}
            },
            storage: {
              set: (k, v) => window.NativeBridge.storageSet(String(k), String(v)),
              get: (k) => window.NativeBridge.storageGet(String(k)),
              remove: (k) => window.NativeBridge.storageRemove(String(k)),
              clear: () => window.NativeBridge.storageClear()
            },
            push: {
              getToken: () => callNative('pushGetToken', []),
              subscribeToTopic: (topic) => callNative('pushSubscribeToTopic', [String(topic)]),
              unsubscribeFromTopic: (topic) => callNative('pushUnsubscribeFromTopic', [String(topic)])
            },
            camera: {
              requestPermission: () => callNative('cameraRequestPermission', []),
              pickImage: () => callNative('cameraPickImage', []),
              takePicture: () => callNative('cameraTakePicture', [])
            },
            file: {
              readAsBase64: (uri) => callNative('fileReadAsBase64', [String(uri)])
            },
            openExternalUrl: (url) => window.NativeBridge.openExternalUrl(String(url))
          };
        })();
    """.trimIndent()
